INSERT INTO `aareview` VALUES (920,1,'This is a simple introduction to elementary algebraic manipulations of exponents, fractions, and a few formulas familiar to students of arithmetic'),(15,21,'This is an awesome notion. You get to learn some very important spanish verbs in a very, extremely short time.'),(177,1,'this is not just s\nimply a test\nbut also a Gatta\nof life'),(5,1,'this is just a test of the reviews system which is a\nlready g'),(1267,1,'this is just a test of the review writing mechanism'),(395,11,'It would be nice to have a sentence example for each of these long words. It would make learning a bit easier.'),(742,1,'Nice set or random Spanish words and cool pics to go with them. It would be nice to have the pronunciations of these words also'),(34,11,'immer wieder sind die Akzente ein Problem. Aber Übung macht den Meister und es wird immer etwas einfacher.'),(5,14,'http://en.wikipedia.org/wiki/Oceania'),(22,1,'Quick check of the authoring reviews facility in general'),(1269,1,'Russian Nouns 3, check out the correct translation for the word contrary, it may be different than what you have here\n'),(1275,1,'lets check out this comment and see how far it makes it'),(1279,1,'is this getting through or check into the database '),(1271,1,'trial with a\nnew line to see how this is proeprly\ndone here');
