INSERT INTO `Biologie II` VALUES ('Pflanzenzelle Zelltyp','Eucyte (Eukaryoten)'),('Pflanzenzelle Chloroplasten','vorhanden'),('Pflanzenzelle Lysosomen','nicht vorhanden'),('Pflanzenzelle Vakuolen','vorhanden'),('Pflanzenzelle Zellwand','vorhanden'),('Pflanzenzelle Zytoskelett','schwach ausgeprägt'),('Pflanzenzelle primäre Stützfunktion','Zellwand'),('Pflanzenzelle Kohlenhydratspeicher','Stärke'),('Pflanzenzelle interzellulärer Kontakt','Plasmodesmen'),('Pflanzenzelle Zellentgiftung','Glyoxysomen'),('Tierzelle Zelltyp','Eucyte (Eukaryoten)'),('Tierzelle Chloroplasten','nicht vorhanden'),('Tierzelle Lysosomen','vorhanden'),('Tierzelle Vakuolen','nicht vorhanden'),('Tierzelle Zellwand','nicht vorhanden'),('Tierzelle Zytoskelett','stark ausgeprägt'),('Tierzelle primäre Stützfunktion','Zytoskelett'),('Tierzelle Kohlenhydratspeicher','Glykogen'),('Tierzelle interzellulärer','Desmosomen'),('Tierzelle Zellentgiftung','Peroxisomen'),('Was ist ein Virus','ein Pathogen'),('Aus was besteht ein Virus','mit Nukleinsäure gefüllt und hat ein Membran aus Proteinen'),('Wie reproduziert sich ein Virus','es dringt sich in eine Zelle des Wirts und tut sich als Ribosom'),('Was bedeutet es wenn ein Virus mutiert','dass es seine Form ändert'),('Was ist die Konsequenz der Virusmutation','der Wirt muss neue Antikörper produzieren'),('Wie kann sich das Immunsystem eines Wirts auf Viruserkrankung vorbereiten','indem der Wirt geimpft wird'),('aus was besteht Impfung','eine kleine Menge oder toten Form des Virus'),('Wie funktioniert Impfung','die Struktur des Virus wird erkannt und die richtigen Antikörper produziert'),('Durschnittsgröße eines Virus','50 nm'),('Was ist eine Bakterie','Organismus ohne Zellkern (Prokaryot)'),('Aus was besteht eine Bakterie','Zellwand, Zellmembran und einer Strähne von DNA'),('was haben kleinere Bakterien','Flagellum'),('was tut der Flagellum','Bewegung zu steuern'),('Wie reproduziert sich eine Bakterie','durch Zellteilung'),('Wie schnell reproduziert sich eine Bakterie','optimal können sich Bakterien aller 20 Minuten verdoppeln'),('Wie kann man sich vor schlechten Bakterien schützen','mit dem passenden Antibiotikum spritzen zu lassen'),('Wie können Bakterien uns helfen','hauptsächlich mit Verdauung und mit der nützlichen Wandlung von Vitaminen und Mineralien'),('Durschnittsgröße einer Bakterie','0,5 x 3 microns'),('Aus was besteht unser Blut','Weißen Blutzellen, Roten Blutzellen, Blutplättchen und aus Blutplasma'),('Wofür sind Weiße Blutzellen zuständig','beschützen uns vor bösartigen Krankheitserreger'),('Wofür sind Rote Blutzellen zuständig','zum Transport von Sauerstoff in unserem Körper'),('Was tun die Blutplättchen in unserem Körper','Wundverschluss wenn wir uns verletzen'),('Wofür dient das Blutplasma in unserem Körper','Flüssigkeit in Blut enthält Blutzellen und Körperchen'),('Woraus besteht das Blutplasma','90 % aus Wasser, 10 % aus Nährstoffe, Mineralstoffe, Vitamine, Hormone, Kohlenstoffdioxid, Harnstoff'),('erste Teil vom Blutkreislauf','Venen leiten Blut durch den Rechten Vorhof, Klappe, Rechte Hauptkammer, Lungen Arterie und Lungen'),('zweite Teil vom Blutkreislauf','Linken Vorhof, Klappe, Linke Hauptkammer, Aorta und Rest des Körpers'),('Was sind Arterien','Strähnen die sauerstoffreiches Blut transportieren vom Herz'),('Was tun Venen','transportieren das Blut zum Herz'),('Was sind Kapillaren','kleinsten Blutgefäße verbinden die Venen mit den Arterien'),('Was tut das Immunsystem','behält einem gesunden Zustand'),('Wie beschützt uns unser Immunsystem vor Viren','die Weißen Blutkörperchen produzieren Antikörper'),('Wie beschützt uns unser Immunsystem vor Bakterien und Entzündungen','Inflammation - Mastzellen produzieren Histamin'),('Was ist Antihistamin','Antihistamin beruhigt die Inflammation'),('Was sind die fünf verschiedenen Nährstoffe','Kohlenhydrate, Eiweiß, Fette, Mineralien und Vitamine'),('sieben verschiedenen Nahrungsgruppen','Vollkornprodukte, Öle, Obst, Gemüse, Nüsse und Hülsenfrüchte, Fleisch und Milchprodukte'),('Was sind Kohlenhydrate','Nährstoffe die uns Glucose geben'),('Was sind Eiweiße','die stofflichen Bausteine von Zellen'),('Aus was bestehen Eiweiße','bis zu 20 verschiedene Aminosäuren'),('Was sind Fette','Energiequelle und Baustoffe'),('Was sind Mineralien','Mikronährstoffe, kleine Helfer im Körper, so wie Enzyme'),('Was sind Vitamine','Mikronährstoffe mit speziellen Funktionen'),('Welchen Nährstoff bieten uns Vollkornprodukte','Ballaststoffen'),('Was sind Ballaststoffe','unverdauliche Nahrungsbestandteile'),('Wie helfen uns Ballaststoffe','Der Magen benutzt sie damit er etwas zu verarbeiten hat'),('Lebensmittel aus purem Zucker','das Zucker geht direkt in unser Blut'),('Konsequenz der puren Zucker Konsumierung','Obstipationen und auf lange dauer Diabetes'),('Welchen Nährstoff bieten uns Öle','Fett'),('Welchen Nährstoff bieten uns Obst und Gemüse','Vitaminen, Mineralien und Kohlenhydrate'),('Welchen Nährstoff bieten uns Nüsse und Hülsenfrüchte','Fette und Eiweiße'),('Welchen Nährstoff bietet uns Fleisch','Eiweiß'),('Welchen Nährstoff bieten Milchprodukte','Kalzium, Fette und Eiweiß'),('erste Schritt der Verdauung','kauen in kleine Stücke'),('zweite Schritt der Verdauung','durch die Speiseröhre in den Magen'),('dritte Schritt der Verdauung','Magensäure löst das Essen in ca. 3 Stunden'),('vierte Schritt der Verdauung','Ballaststoffe - Nährstoffen Trennung und Ballaststoffe zum Dünndarm'),('fünfte Schritt der Verdauung','Ballaststoffe ausgeschieden'),('sechste Schritt der Verdauung','Ballaststoffe zum Dickdarm und Wasser entnommen'),('siebte Schritt der Verdauung','Ballaststoffe zum Mastdarm und ausgeschieden'),('Wie funktioniert Verdauung für Flüssigkeit','nicht zum Magen, sondern zu den Nieren'),('Was machen die Nieren mit der Flüssigkeit','trennen die Nährstoffe von dem was der Mensch nicht brauch'),('Was tut unsere Pankreas','produziert Glucagon und Insulin'),('Was ist Glucagon','Hormon das den Blutzuckerspiegel erhöht'),('Was ist Insulin','Hormon das den Blutzuckerspiegel senkt');
